const webhookData = $('Agent Token Webhook').first().json;

// ── Agent config table ────────────────────────────────────
// Add new agents here. clients = list of client_ids this agent can access.
const AGENTS = {
  admin: { password: '__AGENT_PASSWORD_ADMIN__', clients: ['digishares', 'alkoholcz'], name: 'Admin' },
};

const username = webhookData.body?.username || '';
const password = webhookData.body?.password || '';

if (!username || !password) {
  return [{ json: { valid: false, error: 'Username and password required' } }];
}

const agent = AGENTS[username];
if (!agent || agent.password !== password) {
  return [{ json: { valid: false, error: 'Invalid credentials' } }];
}

return [{ json: { valid: true, identity: 'agent_' + username, clients: agent.clients, name: agent.name } }];

const ACCOUNT_SID    = '__ACCOUNT_SID__';
const API_KEY_SID    = '__API_KEY_SID__';
const SERVICE_SID    = '__SERVICE_SID__';
const TOKEN_TTL      = 1800; // 30 minutes

// Agent identity from validation step
const identity = $('Validate Agent').first().json.identity;

function base64url(str) {
  return btoa(str).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/g, '');
}

const now = Math.floor(Date.now() / 1000);

const header = JSON.stringify({ typ: 'JWT', alg: 'HS256', cty: 'twilio-fpa;v=1' });
const payload = JSON.stringify({
  jti: `${API_KEY_SID}-${now}`,
  iss: API_KEY_SID,
  sub: ACCOUNT_SID,
  iat: now,
  exp: now + TOKEN_TTL,
  grants: {
    identity: identity,
    chat: { service_sid: SERVICE_SID },
  },
});

const headerB64 = base64url(header);
const payloadB64 = base64url(payload);
const unsignedToken = `${headerB64}.${payloadB64}`;

return [{
  json: { unsignedToken },
}];

const unsignedToken = $('Prepare JWT').first().json.unsignedToken;
const hmacBase64 = $json.data;
const agentData = $('Validate Agent').first().json;

// Convert standard base64 to base64url
const sig = hmacBase64.replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/g, '');

const token = `${unsignedToken}.${sig}`;

return [{
  json: {
    token,
    identity: agentData.identity,
    clients: agentData.clients,
    region: 'ie1',
  },
}];
